export const SPELL_LIST: SpellData[] = [...BASE_SPELL_LIST, ...PHB_SUPPLEMENTAL_SPELLS];

export function getSpellsForClass(className: string): SpellData[] {
  return SPELL_LIST.filter(s => s.classes.includes(className));
}

export function getSpellsForClassByLevel(className: string, maxLevel: number): Map<number, SpellData[]> {
  const map = new Map<number, SpellData[]>();
  for (let i = 0; i <= 9; i++) map.set(i, []);
  getSpellsForClass(className).forEach(spell => {
    if (spell.level <= maxLevel) {
      map.get(spell.level)!.push(spell);
    }
  });
  return map;
}
